SELECT COUNT(*) AS numero_servidores FROM servidor s WHERE LOWER(s.categoria) = LOWER('docente') AND LOWER(s.contrato) = LOWER('efetivos') AND LOWER(s.area_ingresso) = LOWER('ciencia da computacao') AND LOWER(s.sigla_campus) = LOWER('ana') AND EXISTS (SELECT 1 FROM calc_hora_aula_media c WHERE c.siape = s.pk_siape AND c.ano = 2021 AND c.semestre = 2 AND LOWER(c.sigla_campus) = LOWER('ana')) AND s.saiu_do_ifg = FALSE